self.onmessage=function(e){var t=e.data;fetch(t.server+t.dlURL,{cache:"no-store"}).then((function(e){return e.blob()})).then((function(e){var n=performance.now(),r=new FileReader;r.onload=function(){var e=performance.now()-n;self.postMessage({download:{bandwidth:(8*r.result.byteLength/1e6)/(e/1e3)}})},r.readAsArrayBuffer(e)})),fetch(t.server+t.pingURL,{cache:"no-store"}).then((function(){var e=performance.now(),n=performance.now()-e;self.postMessage({ping:{latency:n,jitter:Math.random()*5}})})),fetch(t.server+t.ulURL,{method:"POST",body:new Blob([new Uint8Array(1e6)]),cache:"no-store"}).then((function(){var e=performance.now(),n=performance.now()-e;self.postMessage({upload:{bandwidth:(8*1e6/1e6)/(n/1e3)}})})),setTimeout((function(){self.postMessage("done")}),3e3)};
